394→export function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
395→  const entries = parseUpdateObject(r);
396→  for (const entry of entries) {
397→    switch (entry.type) {
398→      case "create": {
399→        const { _changed: _co, ...objFields } = extractObjectFields(
400→          entry.fields,
401→        );
402→        let extraFields: Record<string, unknown> = {};
403→        if (
404→          entry.objectType === ObjectType.UNIT ||
405→          entry.objectType === ObjectType.PLAYER
406→        ) {
407→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
408→          extraFields = rest;
409→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
410→          const { _changed: _cg, ...rest } = extractGameObjectFields(
411→            entry.fields,
412→          );
413→          extraFields = rest;
414→        }
415→        const cachedName = lookupCachedName(
416→          conn,
417→          entry.guid,
418→          entry.objectType,
419→          objFields.entry,
420→        );
421→        conn.entityStore.create(entry.guid, entry.objectType, {
422→          ...objFields,
423→          ...extraFields,
424→          ...(cachedName ? { name: cachedName } : {}),
425→          ...(entry.position ? { position: entry.position } : {}),
426→          rawFields: new Map(entry.fields),
427→        } as any);
428→        if (!cachedName) {
429→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
430→        }
431→        break;
432→      }
433→      case "values": {
434→        const entity = conn.entityStore.get(entry.guid);
435→        if (!entity) break;
436→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
437→        let extraFields: Record<string, unknown> = {};
438→        if (
439→          entity.objectType === ObjectType.UNIT ||
440→          entity.objectType === ObjectType.PLAYER
441→        ) {
442→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
443→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
444→          extraFields = extractGameObjectFields(entry.fields);
445→        }
446→        const allChanged = [
447→          ...(objFields._changed || []),
448→          ...((extraFields as any)._changed || []),
449→        ];
450→        const merged: Record<string, unknown> = {};
451→        for (const key of allChanged) {
452→          if (key in extraFields) merged[key] = (extraFields as any)[key];
453→          else if (key in objFields) merged[key] = (objFields as any)[key];
454→        }
455→        conn.entityStore.update(entry.guid, merged);
456→        for (const [k, v] of entry.fields) {
457→          const existing = conn.entityStore.get(entry.guid);
458→          if (existing) existing.rawFields.set(k, v);
459→        }
460→        break;
461→      }
462→      case "movement": {
463→        conn.entityStore.setPosition(entry.guid, entry.position);
464→        break;
465→      }
466→      case "outOfRange": {
467→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
468→        break;
469→      }
470→      case "nearObjects": {
471→        break;
472→      }
473→    }
474→  }
475→}
