482→  const compressed = r.bytes(r.remaining);
483→  const decompressed = inflateSync(compressed);
484→  if (decompressed.length !== uncompressedSize) {
485→    throw new Error(
486→      `Compressed update size mismatch: expected ${uncompressedSize}, got ${decompressed.length}`,
487→    );
488→  }
489→  handleUpdateObject(conn, new PacketReader(new Uint8Array(decompressed)));
490→}
