498→export function lookupCachedName(
499→  conn: WorldConn,
500→  guid: bigint,
501→  objectType: number,
502→  entry: number | undefined,
503→): string | undefined {
504→  if (objectType === ObjectType.PLAYER) {
505→    const guidLow = Number(guid & 0xffffffffn);
506→    return conn.nameCache.get(guidLow);
507→  }
508→  if (entry === undefined) return undefined;
509→  if (objectType === ObjectType.UNIT) return conn.creatureNameCache.get(entry);
510→  if (objectType === ObjectType.GAMEOBJECT)
511→    return conn.gameObjectNameCache.get(entry);
512→  return undefined;
513→}
