515→export function queryEntityName(
516→  conn: WorldConn,
517→  guid: bigint,
518→  objectType: number,
519→  entry: number | undefined,
520→): void {
521→  if (objectType === ObjectType.PLAYER) {
522→    const guidLow = Number(guid & 0xffffffffn);
523→    const key = `player:${guidLow}`;
524→    if (conn.pendingNameQueries.has(key)) return;
525→    conn.pendingNameQueries.add(key);
526→    const w = new PacketWriter();
527→    w.uint64LE(guid);
528→    sendPacket(conn, GameOpcode.CMSG_NAME_QUERY, w.finish());
529→    return;
530→  }
531→  if (entry === undefined) return;
532→  const key = `${objectType}:${entry}`;
533→  if (conn.pendingNameQueries.has(key)) return;
534→  conn.pendingNameQueries.add(key);
535→  if (objectType === ObjectType.UNIT) {
536→    sendPacket(
537→      conn,
538→      GameOpcode.CMSG_CREATURE_QUERY,
539→      buildCreatureQuery(entry, guid),
540→    );
541→    return;
542→  }
543→  if (objectType === ObjectType.GAMEOBJECT) {
544→    sendPacket(
545→      conn,
546→      GameOpcode.CMSG_GAMEOBJECT_QUERY,
547→      buildGameObjectQuery(entry, guid),
548→    );
549→    return;
550→  }
551→}
