553→export function handleCreatureQueryResponse(
554→  conn: WorldConn,
555→  r: PacketReader,
556→): void {
557→  const result = parseCreatureQueryResponse(r);
558→  conn.pendingNameQueries.delete(`${ObjectType.UNIT}:${result.entry}`);
559→  if (!result.name) return;
560→  conn.creatureNameCache.set(result.entry, result.name);
561→  for (const entity of conn.entityStore.all()) {
562→    if (entity.entry === result.entry && !entity.name) {
563→      conn.entityStore.setName(entity.guid, result.name);
564→    }
565→  }
566→}
567→
568→export function handleGameObjectQueryResponse(
569→  conn: WorldConn,
570→  r: PacketReader,
571→): void {
572→  const result = parseGameObjectQueryResponse(r);
573→  conn.pendingNameQueries.delete(`${ObjectType.GAMEOBJECT}:${result.entry}`);
574→  if (!result.name) return;
575→  conn.gameObjectNameCache.set(result.entry, result.name);
576→  for (const entity of conn.entityStore.all()) {
577→    if (entity.entry === result.entry) {
578→      if (!entity.name) conn.entityStore.setName(entity.guid, result.name);
579→      if (result.gameObjectType !== undefined) {
580→        conn.entityStore.update(entity.guid, {
581→          gameObjectType: result.gameObjectType,
582→        });
583→      }
584→    }
585→  }
586→}
