588→export function handlePartyMemberStatsMsg(
589→  conn: WorldConn,
590→  r: PacketReader,
591→  isFull = false,
592→): void {
593→  const stats = parsePartyMemberStats(r, isFull);
594→  conn.onGroupEvent?.({
595→    type: "member_stats",
596→    guidLow: stats.guidLow,
597→    online: stats.online,
598→    hp: stats.hp,
599→    maxHp: stats.maxHp,
600→    level: stats.level,
601→  });
602→}
603→
604→export function handleContactList(conn: WorldConn, r: PacketReader): void {
605→  const list = parseContactList(r);
606→  const friends: FriendEntry[] = [];
607→  for (const contact of list.contacts) {
608→    if (!(contact.flags & SocialFlag.FRIEND)) continue;
609→    const guidLow = Number(contact.guid & 0xffffffffn);
610→    const name = conn.nameCache.get(guidLow) ?? "";
611→    friends.push({
612→      guid: contact.guid,
613→      name,
614→      note: contact.note,
615→      status: contact.status ?? 0,
616→      area: contact.area ?? 0,
617→      level: contact.level ?? 0,
618→      playerClass: contact.playerClass ?? 0,
619→    });
620→    if (!name) ensureNameQuery(conn, contact.guid);
621→  }
622→  conn.friendStore.set(friends);
623→
624→  const ignored: IgnoreEntry[] = [];
625→  for (const contact of list.contacts) {
626→    if (!(contact.flags & SocialFlag.IGNORED)) continue;
627→    const guidLow = Number(contact.guid & 0xffffffffn);
628→    const name = conn.nameCache.get(guidLow) ?? "";
629→    ignored.push({ guid: contact.guid, name });
630→    if (!name) ensureNameQuery(conn, contact.guid);
631→  }
