635→export function handleFriendStatus(conn: WorldConn, r: PacketReader): void {
636→  const packet = parseFriendStatus(r);
637→  const guidLow = Number(packet.guid & 0xffffffffn);
638→
639→  switch (packet.result) {
640→    case FriendResult.ADDED_ONLINE:
641→    case FriendResult.ADDED_OFFLINE: {
642→      const name = conn.nameCache.get(guidLow) ?? "";
643→      conn.friendStore.add({
644→        guid: packet.guid,
645→        name,
646→        note: packet.note ?? "",
647→        status: packet.status ?? 0,
648→        area: packet.area ?? 0,
649→        level: packet.level ?? 0,
