657→        status: packet.status ?? FriendStatus.ONLINE,
658→        area: packet.area ?? 0,
659→        level: packet.level ?? 0,
660→        playerClass: packet.playerClass ?? 0,
661→      });
662→      break;
663→    case FriendResult.OFFLINE:
